class Solution {
    public int findTheLongestSubstring(String s) {
        Map<Integer, Integer> maskMap = new HashMap<>();
        maskMap.put(0, -1);
        int currentMask = 0;
        int maxLen = 0;

        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            int bit = -1;
            switch (c) {
                case 'a': bit = 0; break;
                case 'e': bit = 1; break;
                case 'i': bit = 2; break;
                case 'o': bit = 3; break;
                case 'u': bit = 4; break;
            }
            if (bit != -1) {
                currentMask ^= (1 << bit);
            }
            if (maskMap.containsKey(currentMask)) {
                int len = i - maskMap.get(currentMask);
                if (len > maxLen) {
                    maxLen = len;
                }
            } else {
                maskMap.put(currentMask, i);
            }
        }
        return maxLen;
    }
}

